using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private OrderService _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new OrderService();
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectTotal()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 10.00m, Quantity = 2 },
            new() { ProductName = "Gadget", Price = 25.50m, Quantity = 1 }
        };

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(45.50m, order.Total);
        Assert.AreEqual(2, order.Items.Count);
        Assert.IsFalse(string.IsNullOrEmpty(order.Id));
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_SetsCreatedAtToUtcNow()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
        };
        var before = DateTime.UtcNow;

        var order = _sut.CreateOrder("cust-1", items);

        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after);
    }

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
        };

        Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder(null!, items));
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder("cust-1", null!));
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        Assert.ThrowsExactly<InvalidOperationException>(
            () => _sut.CreateOrder("cust-1", []));
    }

    [TestMethod]
    public void GetOrder_WithExistingId_ReturnsMatchingOrder()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 10.00m, Quantity = 1 }
        };
        var created = _sut.CreateOrder("cust-1", items);

        var retrieved = _sut.GetOrder(created.Id);

        Assert.IsNotNull(retrieved);
        Assert.AreEqual(created.Id, retrieved.Id);
        Assert.AreEqual(created.Total, retrieved.Total);
    }

    [TestMethod]
    public void GetOrder_WithNonExistentId_ReturnsNull()
    {
        var result = _sut.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_WithMatchingOrders_ReturnsAllCustomerOrders()
    {
        _sut.CreateOrder("cust-1", [new() { ProductName = "A", Price = 1m, Quantity = 1 }]);
        _sut.CreateOrder("cust-1", [new() { ProductName = "B", Price = 2m, Quantity = 1 }]);
        _sut.CreateOrder("cust-2", [new() { ProductName = "C", Price = 3m, Quantity = 1 }]);

        var orders = _sut.GetOrdersByCustomer("cust-1");

        Assert.AreEqual(2, orders.Count);
        Assert.IsTrue(orders.All(o => o.CustomerId == "cust-1"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_WithNoMatchingOrders_ReturnsEmptyList()
    {
        _sut.CreateOrder("cust-1", [new() { ProductName = "A", Price = 1m, Quantity = 1 }]);

        var orders = _sut.GetOrdersByCustomer("cust-999");

        Assert.AreEqual(0, orders.Count);
    }

    [TestMethod]
    public void CreateOrder_MultipleItems_CalculatesTotalCorrectly()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "A", Price = 9.99m, Quantity = 3 },
            new() { ProductName = "B", Price = 4.50m, Quantity = 10 }
        };

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual(9.99m * 3 + 4.50m * 10, order.Total);
    }
}

